demos.key_concepts:
[
  {
    "concept": "ความหมายของ Present Simple Tense",
    "importance": "high",
    "details": "ใช้บรรยายเหตุการณ์ที่เกิดขึ้นในชีวิตประจำวัน เหตุการณ์จริงทั่วไป และกิจกรรมที่เป็นตารางเวลาแน่นอน"
  },
  {
    "concept": "คำบอกเวลาที่พบบ่อยใน Present Simple Tense",
    "importance": "high",
    "details": "เช่น every day, twice a month, always, usually, sometimes ซึ่งช่วยระบุความถี่ของเหตุการณ์"
  },
  {
    "concept": "โครงสร้างประโยคบอกเล่า (Affirmative)",
    "importance": "high",
    "details": "Subject + verb (เติม s/es เมื่อประธานเป็นเอกพจน์) + complement/object เช่น The earth revolves around the sun"
  },
  {
    "concept": "กฎการเติม s/es ที่คำกริยา",
    "importance": "high",
    "details": "เติม -s สำหรับประธานเอกพจน์ทั่วไป เช่น He works; เติม -es สำหรับกริยาที่ลงท้ายด้วย -ch, -sh, -x, -z, -o เช่น watches, fixes, goes"
  },
  {
    "concept": "โครงสร้างประโยคคำถาม (Interrogative)",
    "importance": "high",
    "details": "Do/Does + subject + verb (infinitive) + complement/object เช่น Do you go to school every day?"
  },
  {
    "concept": "การใช้ Wh-question ร่วมกับ Present Simple",
    "importance": "medium",
    "details": "นำ Wh-word (Where, When, Why, etc.) มาวางด้านหน้าประโยค เช่น Where does he work?"
  },
  {
    "concept": "โครงสร้างประโยคปฏิเสธ (Negative)",
    "importance": "high",
    "details": "Subject + do/does (not) + verb (infinitive) + complement/object เช่น The train doesn’t arrive at 7 o’clock"
  },
  {
    "concept": "การเปลี่ยนกริยาให้เป็น infinitive เมื่อใช้ do/does",
    "importance": "high",
    "details": "เมื่อใช้ do/does กริยาแท้ในประโยคจะต้องอยู่ในรูป infinitive (ไม่เติม s/es) เช่น He does not play → ไม่ใช่ He does not plays"
  }
]

[
  {
    "concept": "ระบบไหลเวียนเลือดแบบเปิดและแบบปิด",
    "importance": "high",
    "details": [
      "ระบบที่เลือดไหลเข้าสู่ช่องว่างฮีโมซีล (พบในอาร์โทรโพดาและมอลลัสกา)",
      "ระบบที่เลือดอยู่ในหลอดเลือดตลอดเวลา (พบในไส้เดือนและสัตว์มีกระดูกสันหลัง)"
    ]
  },
  {
    "concept": "โครงสร้างหัวใจมนุษย์ 4 ห้อง",
    "importance": "high",
    "details": [
      "ห้องบนขวา (Right Atrium)",
      "ห้องล่างขวา (Right Ventricle)",
      "ห้องบนซ้าย (Left Atrium)",
      "ห้องล่างซ้าย (Left Ventricle)"
    ]
  },
  {
    "concept": "ลิ้นหัวใจและหน้าที่",
    "importance": "high",
    "details": [
      "Tricuspid Valve (ระหว่างห้องบนขวาและล่างขวา)",
      "Bicuspid/Mitral Valve (ระหว่างห้องบนซ้ายและล่างซ้าย)",
      "Semilunar Valves (ระหว่างห้องล่างซ้ายกับหลอดเลือดใหญ่)"
    ]
  },
  {
    "concept": "เส้นทางการไหลของเลือด",
    "importance": "high",
    "details": [
      "เลือดจากตัวร่างกาย → ห้องบนขวา → ห้องล่างขวา → ปอด (เพื่อแลกเปลี่ยนก๊าซ)",
      "เลือดจากปอด → ห้องบนซ้าย → ห้องล่างซ้าย → ร่างกายทั้งหมด"
    ]
  },
  {
    "concept": "หลอดเลือดต่าง ๆ",
    "importance": "high",
    "details": [
      "หลอดเลือดแดง (Artery): นำเลือดออกจากหัวใจ",
      "หลอดเลือดดำ (Vein): นำเลือดกลับเข้าหัวใจ",
      "หลอดเลือดฝอย (Capillary): แลกเปลี่ยนสารอาหารและก๊าซ"
    ]
  },
  {
    "concept": "ส่วนประกอบของเลือด",
    "importance": "high",
    "details": [
      "พลาสมา (Plasma): ของเหลวที่เป็นฐาน",
      "เซลล์เม็ดเลือดแดง (Erythrocytes): ขนส่งออกซิเจน",
      "เซลล์เม็ดเลือดขาว (Leukocytes): ภูมิคุ้มกัน",
      "เกล็ดเลือด (Thrombocytes): การแข็งตัวของเลือด"
    ]
  },
  {
    "concept": "ระบบไหลเวียนน้ำเหลือง",
    "importance": "medium",
    "details": [
      "ทำงานร่วมกับระบบภูมิคุ้มกัน",
      "ช่วยกำจัดของเสียและเชื้อโรค",
      "มีต่อมน้ำเหลืองเป็นจุดตรวจจับ"
    ]
  },
  {
    "concept": "ภูมิคุ้มกันก่อเอง (Active Immunity)",
    "importance": "medium",
    "details": [
      "เกิดจากการสัมผัสกับแอนติเจน (เช่น วัคซีน)",
      "ออกฤทธิ์ช้าแต่คงอยู่ยาวนาน",
      "มีหน่วยความจำทางภูมิคุ้มกัน"
    ]
  },
  {
    "concept": "ภูมิคุ้มกันรับมา (Passive Immunity)",
    "importance": "medium",
    "details": [
      "ได้รับแอนติบอดีจากภายนอก (เช่น จากแม่ผ่านรกหรือนม)",
      "ออกฤทธิ์ทันทีแต่ระยะสั้น",
      "ไม่มีหน่วยความจำ"
    ]
  }
]

[
  {
    "concept": "นิยามของเมทริกซ์",
    "importance": "high",
    "details": "เมทริกซ์คือกลุ่มของจำนวนที่เรียงเป็นแถวและหลักในรูปสี่เหลี่ยม ใช้สำหรับจัดระเบียบข้อมูล"
  },
  {
    "concept": "มิติของเมทริกซ์ (m x n)",
    "importance": "high",
    "details": "ระบุจำนวนแถว (m) และจำนวนหลัก (n) เช่น เมทริกซ์ 2x3 มี 2 แถว และ 3 หลัก"
  },
  {
    "concept": "การแทนสมาชิกในเมทริกซ์ (aij)",
    "importance": "high",
    "details": "ตำแหน่งแถว i หลัก j เขียนแทนด้วย aij เช่น a₂₃ คือสมาชิกที่อยู่แถวที่ 2 หลักที่ 3"
  },
  {
    "concept": "การบวกและการลบเมทริกซ์",
    "importance": "high",
    "details": "ต้องมีมิติเท่ากัน แล้วดำเนินการทีละตำแหน่ง (element-wise)"
  },
  {
    "concept": "การคูณเมทริกซ์ด้วยจำนวนจริง (Scalar Multiplication)",
    "importance": "high",
    "details": "นำจำนวนจริงคูณกับสมาชิกทุกตัวในเมทริกซ์"
  },
  {
    "concept": "เงื่อนไขการคูณเมทริกซ์ด้วยเมทริกซ์",
    "importance": "high",
    "details": "จำนวนหลักของเมทริกซ์ตัวแรกต้องเท่ากับจำนวนแถวของเมทริกซ์ตัวที่สอง"
  },
  {
    "concept": "มิติของผลลัพธ์จากการคูณเมทริกซ์",
    "importance": "high",
    "details": "ผลลัพธ์จะมีมิติเป็น (แถวตัวหน้า x หลักตัวหลัง)"
  },
  {
    "concept": "การไม่สลับที่ของการคูณเมทริกซ์ (AB ≠ BA)",
    "importance": "medium",
    "details": "การคูณเมทริกซ์ไม่สามารถสลับลำดับได้ เช่น AB อาจไม่เท่ากับ BA"
  },
  {
    "concept": "กฎการตัดออก (Cancellation Law) ไม่เป็นจริงเสมอไป",
    "importance": "medium",
    "details": "ถ้า AB = AC ไม่จำเป็นต้องได้ว่า B = C เนื่องจากเมทริกซ์ไม่มีอินเวอร์สเสมอไป"
  }
]

[
  {
    "concept": "ไฟฟ้าคือพลังงานจากการเคลื่อนที่ของอิเล็กตรอนผ่านตัวนำ",
    "importance": "high"
  },
  {
    "concept": "ไฟฟ้าสถิต (Static Electricity)",
    "importance": "high"
  },
  {
    "concept": "ไฟฟ้ากระแสตรง (DC) – ตัวอย่างเช่น แบตเตอรี่, โซล่าเซลล์",
    "importance": "high"
  },
  {
    "concept": "ไฟฟ้ากระแสสลับ (AC) – ไฟบ้านทั่วไป",
    "importance": "high"
  },
  {
    "concept": "หน่วยวัดไฟฟ้า: โวลต์ (V), แอมแปร์ (A), วัตต์ (W), กิโลวัตต์ชั่วโมง (kWh)",
    "importance": "high"
  },
  {
    "concept": "การคำนวณค่าไฟฟ้าจากหน่วย kWh และอัตราค่าไฟ",
    "importance": "high"
  },
  {
    "concept": "การเปลี่ยนผ่านพลังงานจากเชื้อเพลิงฟอสซิลไปสู่พลังงานหมุนเวียน",
    "importance": "medium"
  },
  {
    "concept": "ประโยชน์ของโซล่าเซลล์: ลดค่าไฟและคาร์บอนฟุตพริ้นท์",
    "importance": "medium"
  },
  {
    "concept": "การบริหารจัดการพลังงานในบ้านยุค 2026 ด้วยความเข้าใจพื้นฐานไฟฟ้า",
    "importance": "medium"
  }
]

[
  {
    "concept": "คุณภาพการนอน vs ระยะเวลาการนอน",
    "importance": "high",
    "details": "การนอนครบ 8 ชั่วโมงไม่จำเป็นต้องทำให้ตื่นมาสดชื่น หากคุณภาพการนอนต่ำ โดยเฉพาะการขาดระยะหลับลึก"
  },
  {
    "concept": "ระยะหลับลึก (Deep Sleep)",
    "importance": "high",
    "details": "เป็นระยะการนอนที่ร่างกายฟื้นฟูเซลล์ สมองทำความสะอาด และเสริมสร้างความจำ ขาดระยะนี้ทำให้รู้สึกง่วงตลอดวัน"
  },
  {
    "concept": "สาเหตุของการไม่เข้าสู่ระยะหลับลึก",
    "importance": "high",
    "details": [
      "ความเครียด (Stress)",
      "แสงจากหน้าจอ (Blue light exposure)",
      "ภาวะหยุดหายใจขณะหลับ (Sleep Apnea)",
      "นาฬิกาชีวิตที่ผิดปกติ (Circadian rhythm disruption)"
    ]
  },
  {
    "concept": "ความสัมพันธ์ระหว่างวัยกับชั่วโมงการนอนที่เหมาะสม",
    "importance": "medium",
    "details": "ผู้ใหญ่ควรนอน 7–9 ชั่วโมง แต่ช่วงเวลานี้อาจเปลี่ยนแปลงตามอายุ เช่น เด็กโต วัยรุ่น ผู้สูงอายุ"
  },
  {
    "concept": "Sleep Hygiene (สุขอนามัยการนอน)",
    "importance": "high",
    "details": [
      "เข้านอนและตื่นให้ตรงเวลาทุกวัน",
      "เลี่ยงอาหารหนักและเครื่องดื่มกระตุ้นก่อนนอน 2–4 ชั่วโมง",
      "ลดการใช้มือถือหรือหน้าจอสีฟ้าก่อนนอน",
      "จัดสภาพแวดล้อมห้องให้มืด สงบ ไม่มีเสียงรบกวน"
    ]
  },
  {
    "concept": "เทคนิคผ่อนคลายเพื่อการนอน",
    "importance": "medium",
    "details": "เช่น การหายใจลึก ๆ การทำสมาธิ หรือการฟังเสียงธรรมชาติ"
  },
  {
    "concept": "CBT-I (Cognitive Behavioral Therapy for Insomnia)",
    "importance": "medium",
    "details": "การบำบัดทางจิตใจที่ช่วยปรับความคิดและพฤติกรรมที่ส่งผลต่อการนอน เช่น การหลีกเลี่ยงการนอนไม่หลับด้วยการนั่งรอจนง่วง"
  }
]

[
  {
    "concept": "ความหมายของธาตุ (Element)",
    "importance": "high",
    "details": [
      "สารบริสุทธิ์เนื้อเดียวที่มีองค์ประกอบอย่างเดียว",
      "ไม่สามารถแยกสลายด้วยวิธีทางเคมี",
      "มีสัญลักษณ์แทน เช่น Zn, Pb, Ag"
    ]
  },
  {
    "concept": "สถานะของธาตุในธรรมชาติ",
    "importance": "high",
    "details": [
      "ของแข็ง: Zn, Pb, Ag, Sn",
      "ของเหลว: Hg",
      "ก๊าซ: N₂, He, O₂, H₂"
    ]
  },
  {
    "concept": "การแบ่งธาตุตามสมบัติ: โลหะ อโลหะ กึ่งโลหะ",
    "importance": "high",
    "details": [
      "ธาตุโลหะ: มันวาว นำไฟฟ้า-ความร้อนได้ดี จุดเดือด-หลอมเหลวสูง (ยกเว้น Hg)",
      "ธาตุอโลหะ: ไม่มันวาว ไม่นำไฟฟ้า จุดเดือด-หลอมเหลวต่ำ",
      "ธาตุกึ่งโลหะ: B, Si — มีลักษณะกลาง"
    ]
  },
  {
    "concept": "ความหมายของสารประกอบ (Compound)",
    "importance": "high",
    "details": [
      "เกิดจากธาตุตั้งแต่ 2 ชนิดขึ้นไป",
      "แยกสลายได้ด้วยวิธีทางเคมี",
      "มีสมบัติเฉพาะตัวที่ต่างจากธาตุเดิม"
    ]
  },
  {
    "concept": "ตัวอย่างสารประกอบและสูตรเคมี",
    "importance": "high",
    "details": [
      "น้ำ (H₂O): H:O = 1:8 โดยมวล",
      "น้ำตาลทราย: C, H, O",
      "คาร์บอนไดออกไซด์ (CO₂): C:O = 3:8 โดยมวล"
    ]
  },
  {
    "concept": "สถานะของสารประกอบ",
    "importance": "medium",
    "details": [
      "ของแข็ง: Glucose (C₆H₁₂O₆), Limestone (CaCO₃)",
      "ของเหลว: Ethanol (C₂H₅OH), Acetone (CH₃COCH₃)",
      "ก๊าซ: Methane (CH₄), Sulfur dioxide (SO₂)"
    ]
  },
  {
    "concept": "ความหมายของของผสม (Mixture)",
    "importance": "high",
    "details": [
      "สารที่ไม่บริสุทธิ์ ประกอบด้วยสารตั้งแต่ 2 ชนิดขึ้นไป",
      "สามารถแยกได้ง่ายด้วยวิธีฟิสิกส์",
      "ไม่มีอัตราส่วนคงที่"
    ]
  },
  {
    "concept": "ตัวอย่างของผสม",
    "importance": "high",
    "details": [
      "อากาศ: N₂, O₂, ก๊าซอื่น",
      "น้ำเกลือ: น้ำ + เกลือ",
      "ทองเหลือง: Cu + Zn",
      "พริกกับเกลือ"
    ]
  },
  {
    "concept": "การเปรียบเทียบสมบัติของธาตุและสารประกอบ",
    "importance": "high",
    "details": [
      "ธาตุ: อะตอมชนิดเดียว, แยกด้วยวิธีนิวเคลียร์ได้, เขียนด้วยสัญลักษณ์",
      "สารประกอบ: อะตอมตั้งแต่ 2 ชนิดขึ้นไป, แยกด้วยวิธีเคมีได้, เขียนด้วยสูตร"
    ]
  }
]

[
  {
    "concept": "พระราชสมภพและชื่อเดิมของพระบาทสมเด็จพระจุลจอมเกล้าเจ้าอยู่หัว",
    "importance": "high"
  },
  {
    "concept": "พระราชบิดาและพระราชมารดา",
    "importance": "high"
  },
  {
    "concept": "ช่วงเวลาและเหตุการณ์การเสด็จสวรรคตของพระบาทสมเด็จพระจอมเกล้าเจ้าอยู่หัว (รัชกาลที่ 4)",
    "importance": "high"
  },
  {
    "concept": "การสถาปนาเป็นพระมหากษัตริย์ขณะอายุ 15 พรรษา",
    "importance": "high"
  },
  {
    "concept": "การแต่งตั้งสมเด็จเจ้าพระยาบรมมหาศรีสุริยวงศ์ เป็นผู้สำเร็จราชการแผ่นดิน",
    "importance": "high"
  },
  {
    "concept": "การเสด็จออกว่าราชการอย่างเต็มพระทัยเมื่ออายุ 20 พรรษา",
    "importance": "high"
